class Solution {
public:
    int binaryGap(int n) {
        int last = -1, ans = 0;
        for (int i = 0; n; i++, n >>= 1) {
            if (n & 1) {
                if (last != -1) ans = max(ans, i - last);
                last = i;
            }
        }
        return ans;
    }
};
